mapper.select:
SELECT COALESCE(SUM(CASE WHEN DATE(deal_time) = CURDATE() THEN final_amount ELSE 0 END), 0) AS todayAmount, COALESCE(SUM(CASE WHEN YEARWEEK(deal_time, 1) = YEARWEEK(CURDATE(), 1) THEN final_amount ELSE 0 END), 0) AS weekAmount, COALESCE(SUM(CASE WHEN DATE_FORMAT(deal_time, '%Y-%m') = DATE_FORMAT(CURDATE(), '%Y-%m') THEN final_amount ELSE 0 END), 0) AS monthAmount, COALESCE(SUM(final_amount), 0) AS totalAmount, COALESCE((SELECT SUM(CASE WHEN DATE(vl.operate_time) = CURDATE() THEN (vl.verification_count * COALESCE(CASE WHEN vl.meal_type IN ('LUNCH', 'DINNER') THEN o.lunch_dinner_price ELSE o.breakfast_price END, 0)) ELSE 0 END) FROM meal_verification_log vl LEFT JOIN customer_order o ON vl.order_id = o.id WHERE vl.deleted = 0), 0) AS todayVerificationAmount, COALESCE((SELECT SUM(CASE WHEN YEARWEEK(vl.operate_time, 1) = YEARWEEK(CURDATE(), 1) THEN (vl.verification_count * COALESCE(CASE WHEN vl.meal_type IN ('LUNCH', 'DINNER') THEN o.lunch_dinner_price ELSE o.breakfast_price END, 0)) ELSE 0 END) FROM meal_verification_log vl LEFT JOIN customer_order o ON vl.order_id = o.id WHERE vl.deleted = 0), 0) AS weekVerificationAmount, COALESCE((SELECT SUM(CASE WHEN DATE_FORMAT(vl.operate_time, '%Y-%m') = DATE_FORMAT(CURDATE(), '%Y-%m') THEN (vl.verification_count * COALESCE(CASE WHEN vl.meal_type IN ('LUNCH', 'DINNER') THEN o.lunch_dinner_price ELSE o.breakfast_price END, 0)) ELSE 0 END) FROM meal_verification_log vl LEFT JOIN customer_order o ON vl.order_id = o.id WHERE vl.deleted = 0), 0) AS monthVerificationAmount, COALESCE((SELECT SUM(vl.verification_count * COALESCE(CASE WHEN vl.meal_type IN ('LUNCH', 'DINNER') THEN o.lunch_dinner_price ELSE o.breakfast_price END, 0)) FROM meal_verification_log vl LEFT JOIN customer_order o ON vl.order_id = o.id WHERE vl.deleted = 0), 0) AS totalVerificationAmount FROM customer_order WHERE status != 0 AND deal_time IS NOT NULL
AND DATE(deal_time) >= #{startDate} AND DATE(deal_time) <= #{endDate}
AND DATE(deal_time) >= #{startDate}
AND DATE(deal_time) <= #{endDate}

SELECT COALESCE(pp.package_name, '') AS name, COALESCE(SUM(COALESCE(o.breakfast_count, 0) + COALESCE(o.lunch_dinner_count, 0)), 0) AS value FROM customer_order o LEFT JOIN parent_package pp ON o.parent_package_id = pp.id WHERE o.status != 0 AND o.deal_time IS NOT NULL
AND DATE(o.deal_time) >= #{startDate}
AND DATE(o.deal_time) <= #{endDate}
GROUP BY o.parent_package_id, pp.package_name ORDER BY value DESC

SELECT COALESCE(pp.package_name, '') AS name, COALESCE(SUM(o.final_amount), 0) AS value FROM customer_order o LEFT JOIN parent_package pp ON o.parent_package_id = pp.id WHERE o.status != 0 AND o.deal_time IS NOT NULL
AND DATE(o.deal_time) >= #{startDate}
AND DATE(o.deal_time) <= #{endDate}
GROUP BY o.parent_package_id, pp.package_name ORDER BY value DESC

SELECT COALESCE(pp.package_name, '') AS name, COALESCE(SUM(o.final_amount), 0) AS value FROM customer_order o LEFT JOIN parent_package pp ON o.parent_package_id = pp.id WHERE o.status != 0 AND o.deal_time IS NOT NULL
AND DATE(o.deal_time) >= #{startDate}
AND DATE(o.deal_time) <= #{endDate}
GROUP BY o.parent_package_id, pp.package_name ORDER BY value DESC

SELECT COALESCE(dd.label, o.customer_source) AS name, COALESCE(SUM(o.final_amount), 0) AS value FROM customer_order o LEFT JOIN sys_dict d ON d.name = 'customer_source' LEFT JOIN sys_dict_detail dd ON dd.dict_id = d.dict_id AND dd.value = o.customer_source WHERE o.status != 0 AND o.deal_time IS NOT NULL AND o.customer_source IS NOT NULL AND o.customer_source != ''
AND DATE(o.deal_time) >= #{startDate}
AND DATE(o.deal_time) <= #{endDate}
GROUP BY o.customer_source, dd.label ORDER BY value DESC

SELECT o.id, DATE_FORMAT(o.deal_time, '%Y-%m-%d %H:%i:%s') AS saleDate, COALESCE(sp.sub_package_name, '') AS productName, o.main_dish_count, o.side_dish_count, o.veg_count, o.rice_count, o.soup_count, (COALESCE(o.breakfast_count, 0) + COALESCE(o.lunch_dinner_count, 0)) AS mealCount, o.customer_code AS customerRemark, o.final_amount AS saleAmount, COALESCE(dd.label, o.customer_source) AS channelName, COALESCE(pp.package_name, '') AS salespersonName FROM customer_order o LEFT JOIN parent_package pp ON o.parent_package_id = pp.id LEFT JOIN sub_package sp ON o.child_package_id = sp.id LEFT JOIN sys_dict d ON d.name = 'customer_source' LEFT JOIN sys_dict_detail dd ON dd.dict_id = d.dict_id AND dd.value = o.customer_source
o.status != 0 AND o.deal_time IS NOT NULL
AND DATE(o.deal_time) >= #{criteria.startDate}
AND DATE(o.deal_time) <= #{criteria.endDate}
AND o.customer_source = #{criteria.customerSource}
AND o.parent_package_id = #{criteria.parentPackageId}
AND o.child_package_id = #{criteria.childPackageId}
ORDER BY o.deal_time DESC, o.id DESC
LIMIT #{criteria.offset}, #{criteria.size}

SELECT COUNT(1)
FROM customer_order o

    o.status != 0
    AND o.deal_time IS NOT NULL

        AND DATE(o.deal_time) >= #{criteria.startDate}


        AND DATE(o.deal_time) <= #{criteria.endDate}


        AND o.customer_source = #{criteria.customerSource}


        AND o.parent_package_id = #{criteria.parentPackageId}


        AND o.child_package_id = #{criteria.childPackageId}

SELECT COALESCE(dd.label, o.customer_source) AS channelName, COUNT(1) AS orderCount, COALESCE(SUM(o.final_amount), 0) AS saleAmount FROM customer_order o LEFT JOIN sys_dict d ON d.name = 'customer_source' LEFT JOIN sys_dict_detail dd ON dd.dict_id = d.dict_id AND dd.value = o.customer_source
o.status != 0 AND o.customer_source = #{customerSource} AND o.deal_time IS NOT NULL
AND DATE(o.deal_time) >= #{startDate}
AND DATE(o.deal_time) <= #{endDate}
GROUP BY o.customer_source, dd.label

SELECT COALESCE(pp.package_name, '') AS salespersonName, COUNT(1) AS orderCount, COALESCE(SUM(o.final_amount), 0) AS saleAmount FROM customer_order o LEFT JOIN parent_package pp ON o.parent_package_id = pp.id
o.status != 0 AND o.parent_package_id = #{parentPackageId} AND o.deal_time IS NOT NULL
AND DATE(o.deal_time) >= #{startDate}
AND DATE(o.deal_time) <= #{endDate}
